const body = $json.body || $json;
const required = ['requestId', 'imageBase64', 'selectedDocumentType', 'documentSide', 'profile'];
const missing = required.filter((key) => !body[key]);
if (missing.length) {
  return [{ json: {
    requestId: body.requestId || 'missing_request_id',
    source: 'n8n',
    googleDriveFolderId: body.googleDriveFolderId || '1vn1OXPH2al136Us9th9LHR96nwIqHLQd',
    userMessage: 'We could not start identity verification because required data was missing.',
    analysis: {
      documentDetected: false,
      userSelectedType: body.selectedDocumentType || 'unknown',
      userSelectedTypeLabel: 'Selected document',
      detectedDocumentType: 'unknown',
      detectedDocumentTypeLabel: 'Unsupported document',
      documentTypeMatch: false,
      detectedSide: body.documentSide || 'front',
      extractedFields: {},
      validationResults: {
        nameMatch: { status: 'NOT_CHECKED' },
        dobMatch: { status: 'NOT_CHECKED' },
        addressMatch: { status: 'NOT_CHECKED' },
        expirationStatus: 'UNKNOWN',
        photoIntegrity: 'ABSENT'
      },
      flags: missing.map((key) => ({ severity: 'CRITICAL', code: 'MISSING_FIELD', message: `Missing required field: ${key}` })),
      complianceEligibility: false,
      nextAction: 'HALT_VERIFICATION',
      humanReviewRequired: true,
      reviewReason: 'Missing required identity verification input.'
    }
  }}];
}
const imageBase64 = String(body.imageBase64).replace(/^data:image\/[a-zA-Z0-9.+-]+;base64,/, '');
return [{
  json: {
    ...body,
    googleDriveFolderId: body.googleDriveFolderId || '1vn1OXPH2al136Us9th9LHR96nwIqHLQd',
    uploadedFileName: `${body.requestId}-${body.selectedDocumentType}-${body.documentSide}.png`
  },
  binary: {
    idImage: {
      data: imageBase64,
      mimeType: 'image/png',
      fileName: `${body.requestId}-${body.selectedDocumentType}-${body.documentSide}.png`
    }
  }
}];

const input = $items('Validate Input + Prepare Image')[0].json;
const drive = $items('Upload ID Image To Google Drive')[0].json;
const labels = {
  'drivers-license': 'US Driver’s License',
  'state-id': 'US State ID Card',
  passport: 'US Passport',
  'passport-card': 'US Passport Card',
  'permanent-resident-card': 'US Permanent Resident Card',
  'employment-authorization-card': 'US Employment Authorization Card',
  'military-id': 'US Military ID',
  unknown: 'Unsupported document'
};
const raw = $json;
const detectedType = raw.detectedDocumentType || 'unknown';
const selectedLabel = labels[input.selectedDocumentType] || labels.unknown;
const detectedLabel = raw.detectedDocumentTypeLabel || labels[detectedType] || labels.unknown;
const documentTypeMatch = Boolean(raw.documentTypeMatch ?? detectedType === input.selectedDocumentType);
const flags = Array.isArray(raw.flags) ? raw.flags : [];
if (!raw.documentDetected) {
  flags.push({ severity: 'CRITICAL', code: 'NO_DOCUMENT_DETECTED', message: 'No supported US government ID detected. Hold the selected document inside the frame and capture the correct side.' });
}
if (raw.documentDetected && !documentTypeMatch) {
  flags.push({ severity: 'CRITICAL', code: 'DOCUMENT_TYPE_MISMATCH', message: `DOCUMENT_TYPE_MISMATCH: User selected ${selectedLabel}, but image detects ${detectedLabel}. Verification halted.` });
}
const critical = flags.some((flag) => flag.severity === 'CRITICAL');
const userMessage = raw.userMessage || (critical ? 'We found a problem with this ID. Review the feedback and retake the photo or correct your profile.' : 'This ID looks good and matches your profile.');
return [{ json: {
  requestId: input.requestId,
  source: 'n8n',
  googleDriveFolderId: input.googleDriveFolderId,
  googleDriveFileId: drive.id || drive.fileId || null,
  userMessage,
  analysis: {
    documentDetected: Boolean(raw.documentDetected),
    userSelectedType: input.selectedDocumentType,
    userSelectedTypeLabel: selectedLabel,
    detectedDocumentType: detectedType,
    detectedDocumentTypeLabel: detectedLabel,
    documentTypeMatch,
    detectedSide: raw.detectedSide || input.documentSide,
    extractedFields: raw.extractedFields || {},
    validationResults: raw.validationResults || {
      nameMatch: { status: 'NOT_CHECKED' },
      dobMatch: { status: 'NOT_CHECKED' },
      addressMatch: { status: 'NOT_CHECKED' },
      expirationStatus: 'UNKNOWN',
      photoIntegrity: 'ANOMALY'
    },
    flags,
    complianceEligibility: Boolean(raw.complianceEligibility ?? !critical),
    nextAction: raw.nextAction || (critical ? 'HALT_VERIFICATION' : 'CONTINUE'),
    humanReviewRequired: Boolean(raw.humanReviewRequired ?? critical),
    reviewReason: raw.reviewReason || flags.find((flag) => flag.severity === 'CRITICAL')?.message
  }
}}];
